    @typing.overload
    def decode_return_value(
        self,
        method: typing.Literal["bootstrap(pay)uint64"],
        return_value: algokit_utils.ABIReturn | None
    ) -> int | None: ...
    @typing.overload
    def decode_return_value(
        self,
        method: typing.Literal["mint(address,uint64)void"],
        return_value: algokit_utils.ABIReturn | None
    ) -> None: ...
    @typing.overload
    def decode_return_value(
        self,
        method: typing.Literal["retire(uint64,axfer,pay)void"],
        return_value: algokit_utils.ABIReturn | None
    ) -> None: ...
